from num2words import num2words
from itertools import count, islice
def n2w(n): return "".join(c for c in num2words(n).replace(" and", "") if c.isalpha())
def agen():
    tot = 0
    for n in count(1):
        tot += len(n2w(n))
        yield tot + n
print(list(islice(agen(), 69))) # _Michael S. Branicky_, Jun 02 2026

